+package compiler.c2.igvn;
+
+/*
+ * @test
+ * @bug JDK-8375645
+ * @summary In PhiNode::Ideal, we attempt to split phis through memory merges.
+ *          While doing that, we might end up creating new phis that conflict
+ *          with existing ones (same region and slice). This creates an
+ *          ambiguity that confuses escape analysis.
+ * @run main/othervm -Xbatch -XX:-TieredCompilation
+ *      -XX:+IgnoreUnrecognizedVMOptions -XX:+VerifyAmbiguousMemPhi
+ *      -XX:CompileCommand=compileonly,${test.main.class}::test
+ *      ${test.main.class}
+ * @run main ${test.main.class}
+ *
+ */
+
+public class TestDuplicatePhiNpe {
+    public static void main(String[] args) {
+        for (int i = 0; i < 200; i++) {
+            test(i%2==0);
+        }
+    }
+
+    private static void test(boolean flag) {
+        A a = null;
+        if (flag) {
+            C c = new C();
+            B b = new B();
+            for (int i = 0; i < 4; i++) {
+                for (int j = 0; j < 8; j++) {
+                    switch (i) {
+                        case -1, -2, -3 :
+                            break;
+                        case 0 :
+                            b.c = c;
+                    }
+                }
+            }
+            b.c = c;
+            for (int i = 0; i < 4; i++) {
+                for (int j = 0; j < 8; j++) {
+                    switch (i) {
+                        case -1, -2, -3 :
+                            break;
+                        case 0 :
+                            a = new A();
+                    }
+                }
+            }
+            for (int i = 0; i < 32; i++) {
+                if (i < 10) {
+                    a = new A();
+                }
+            }
+            a = new A();
+            for (int i = 1; i < 32; i++) {
+                a = new A();
+            }
+            for (int i = 1; i < 32; i++) {
+                a = new A();
+            }
+            for (int i = 1; i < 32; i++) {
+                a = new A();
+            }
+
+            for (int i = 0; i < 4; i++) {
+                for (int j = 0; j < 8; j++) {
+                    switch (i) {
+                        case -1, -2, -3 :
+                            break;
+                        case 0 :
+                            a.b = b;
+                    }
+                }
+            }
+            a.b = b;
+        }
+
+        if (a != null) {
+            for (int i = 0; i < 4; i++) {
+                for (int j = 0; j < 8; j++) {
+                    switch (i) {
+                        case -1, -2, -3 :
+                            break;
+                        case 0 :
+                            a.b.c.f = java.lang.Integer.valueOf(0x42);
+                    }
+                }
+            }
+
+            a.b.c.f = java.lang.Integer.valueOf(0x42); // should not throw a NPE
+        }
+    }
+
+    private static class A {
+        public B b;
+    }
+
+    private static class B {
+        public C c;
+    }
+
+    private static class C {
+        public int f;
+    }
+}
